const crypto = require('crypto');
const d = $input.first().json;
const today = new Date().toISOString().split('T')[0];

// Termin platnosci: 7 dni od wystawienia
const due = new Date();
due.setDate(due.getDate() + 7);
const dueDate = due.toISOString().split('T')[0];

const payload = {
  Zaplacono: 1,
  ZaplaconoNaDokumencie: d.amount,
  LiczOd: 'BRT',
  DataWystawienia: today,
  DataSprzedazy: today,
  TerminPlatnosci: dueDate,
  SposobZaplaty: 'PRZ',
  RodzajPodpisuOdbiorcy: 'OUP',
  Kontrahent: {
    Nazwa: d.invoiceCompany || d.email,
    NIP: d.invoiceNip,
    Ulica: d.invoiceAddress || '-',
    KodPocztowy: d.invoicePostalCode || '00-000',
    Miejscowosc: d.invoiceCity || '-',
    KodKraju: d.invoiceCountry || 'PL',
    Email: d.email
  },
  Pozycje: [
    {
      NazwaPelna: d.productName,
      Jednostka: 'szt.',
      Ilosc: 1,
      CenaBrutto: d.amount,
      StawkaVat: 23
    }
  ]
};

// Generowanie HMAC-SHA1 dla iFirma API
const url = 'https://panel.ifirma.pl/iapi/fakturavat.json';
const apiKey = Buffer.from($vars.IFIRMA_API_KEY, 'hex');
const body = JSON.stringify(payload);
const hmac = crypto.createHmac('sha1', apiKey).update(url + body).digest('hex');
const authHeader = `IAPIS user=${$vars.IFIRMA_LOGIN},hmac-sha1=${hmac}`;

return [{
  json: {
    ...payload,
    _body: body,
    _authHeader: authHeader,
    _meta: {
      sessionId: d.sessionId,
      paymentIntentId: d.paymentIntentId,
      buyerEmail: d.email
    }
  }
}];
